/* <flatten type="Javascript"> */
function load$GridVoucherCharge$(z) {
  z.add_itemValueChanged(onChange$GridVoucherCharge$);
  z.add_onResponseComplete(on$GridVoucherCharge$ResponseComplete);
  z.add_commandEvent(on$GridVoucherCharge$ExecuteCommand);

  z.$a = {
    tien_cp: '[tien_cp]:=[tien_cp_nt]*[$ty_gia]',
    thue_nt: '[t_thue_nt]:=[tien_cp_nt]*[thue_suat]/100',
    thue: '[t_thue]:=[tien_cp]*[thue_suat]/100',
