  };
  udf$Detail$(z);
}

function onChange$GridVoucherCharge$(sender, eventArgs) {
  var o = eventArgs.get_object(), z = o.grid, f = z.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'tien_cp_nt':
      z.validExpression(o, [z.$a.tien_cp, z.$a.thue_nt, z.$a.thue], null, null, 't_thue_nt');
      break;
    case 't_thue_nt':
      z.validExpression(o, [z.$a.thue, z.$a.thue_tg]);
      break;
    case 'tien_cp':
      z.validExpression(o, [z.$a.thue], null, null, 't_thue');
      break;
    default:
      break;
  }
}
function on$GridVoucherCharge$ExecuteCommand(sender, e) {
  var action = e.type.Action, z = sender, f = z.get_element().parentForm, v = $func.trim(f.getItem("loai_ct").value);
  switch (action) {
    case 'AfterCloneRow':
      z.setItemFieldValue('stt_rec0', e.type.Value, '');
      var t = z._getColumnOrder('tk_du'), value = z._getItemValue(z._activeRow, t), line = z._getColumnOrder('hd_ln');
      if (v == '1') z._setItemValue(z._activeRow, line, ((value == '') ? z._activeRow: null));
      break;
    case 'AfterInsertRow':
      setDefault$Voucher$Charge(f);
    case 'Check':
      if !(z.validRowExpression('so_ct0', '(([t_thue_nt] == 0) && ([t_thue] == 0)) || ([so_ct0] != "")')) break;
      if !(z.validRowExpression('ngay_ct0', '(([t_thue_nt] == 0) && ([t_thue] == 0)) || ([ngay_ct0] != null)')) break;
      if (v != '1') z.validRowExpression('tk_du', '([tk_du] != "")');
      break;
    default:
      break;
  }
}
function on$GridVoucherCharge$ResponseComplete(sender, e) {
  var z = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = z.get_element().parentForm;
  switch (context) {
    case 'Charge':
      z.setItemGridBehavior(o, [
        ['ma_thue', result[0].Value, '', true],
        ['thue_suat', result[1].Value, null, null]
      ]);
      z.validExpression(o, [z.$a.thue_nt, z.$a.thue], null, null, 'tien_cp_nt');
      break;
    default:
      break;
  }
}
function dispose$GridVoucherCharge$(z) {
  z.$a = null;
  try {z.remove_commandEvent(on$GridVoucherCharge$ExecuteCommand);} catch (ex) {}
  try {z.remove_onResponseComplete(on$GridVoucherCharge$ResponseComplete);} catch (ex) {}
  try {z.remove_itemValueChanged(onChange$GridVoucherCharge$);} catch (ex) {}
}
function setDefault$Voucher$Charge(f) {
  var z = f.getItem("f46")._controlBehavior, r = z._rowCount, c = 'tk_du';
  if ($func.trim(f.getItemValue('loai_ct')) == '1' && (f.getItemValue('tk_cn_ex') != 0)) return;
  if (r == 1) {
    var i = z._getItem(r, 1);
    i.row = r;
    z.setItemGridBehavior(i, [[c, f.getItemValue('tk_ex'), f.getItemValue('ten_tk_ex'), false]]);
  }
}
function onChange$GridVoucherCharge$Code(o) {o.grid.request(o, 'Charge', 'Charge', ['ma_cp'], o);}
